// Small K + small N fast path: vectorize along N (output channels)
// No input reorder, no K-axis reduction. One pass of K iterations with strided weight loads.
if (wt_row_num <= 128 && size <= 128) {
    const int32_t round_val = NN_ROUND(out_rshift);

    // Init accumulator V8/M4 (e32) from bias (q7_t): widen s8 -> s16 -> s32, lshift, add round
    NDS_VEC_VSETVLI(vl, wt_row_num, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VLB_V(NDS_VEC_V0, bias);
    NDS_VEC_VSETVLI(vl, wt_row_num, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
    NDS_VEC_VSEXT_VF2(NDS_VEC_V4, NDS_VEC_V0);
    NDS_VEC_VSETVLI(vl, wt_row_num, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
    NDS_VEC_VSEXT_VF2(NDS_VEC_V8, NDS_VEC_V4);
    NDS_VEC_VSLL_VX(NDS_VEC_V8, NDS_VEC_V8, bias_lshift);
    NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, round_val);

    // Accumulate K MACs: for each k, strided-load column across N rows
    for (uint32_t k = 0; k < size; k++) {
        NDS_VEC_VSETVLI(vl, wt_row_num, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VLSB_V(NDS_VEC_V0, wt_mat + k, size);
