        NDS_VEC_VWMACC_VX(NDS_VEC_V8, in_vec[k], NDS_VEC_V16);
    }

    // Shift-right (out_rshift), clip to q15 range, narrow to s16, store
    NDS_VEC_VSETVLI(vl, wt_row_num, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
    NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
    NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, Q15_MIN);
